import{_ as t,o as i,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"89. Supervision And Management","description":"","frontmatter":{"title":"89. Supervision And Management","eba":"Allied Health Professionals 2021-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/allied-health/classification-staffing/89-supervision-and-management.md","filePath":"ebas/allied-health/classification-staffing/89-supervision-and-management.md"}'),a={name:"ebas/allied-health/classification-staffing/89-supervision-and-management.md"};function n(r,e,l,p,c,h){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_89-supervision-and-management" tabindex="-1">89. Supervision And Management <a class="header-anchor" href="#_89-supervision-and-management" aria-label="Permalink to &quot;89. Supervision And Management&quot;">​</a></h1><p><strong>89.1</strong> General</p><p><strong>(a)</strong> The Employer will ensure that all Employees receive clinical supervision as follows:</p><p><strong>(i)</strong> for Grade / Level / Class 1 and 2 Employees, in accordance with subclauses 89.2 and 89.3 below; and</p><p><strong>(ii)</strong> for Grade / Level / Class 3 Employees and above, in accordance with subclause 89.4 below.</p><p><strong>(b)</strong> In this clause 89, clinical supervision refers to structured professional support, such as:</p><p><strong>(i)</strong> the provision of advice and feedback on clinical matters relating to their profession;</p><p><strong>(ii)</strong> reflective practice;</p><p><strong>(iii)</strong> teaching and learning (both direct and indirect) at point-of-care; and</p><p><strong>(iv)</strong> facilitation of professional development; which may be internal or external.</p><p><strong>89.2</strong> Grade / Level / Class 1 and 2 Employees</p><p><strong>(a)</strong> Employees at Grade / Level / Class 1 and 2 will receive clinical supervision from an Employee in their profession at Grade / Level / Class 3 or above (or equivalent), subject to the transitional provisions at 89.3 below.</p><p><strong>(b)</strong> With respect to Grade / Level / Class 1 Employees, such supervision can be directly provided by a Grade / Level / Class 3 Employee on a day to day basis or through a Grade/Level/Class 2 Employee who will provide the direct clinical supervision on a day to day basis in accordance with <a href="/eba/ebas/allied-health/appendices/4-classification-definitions.html">Appendix 4</a>.</p><p><strong>89.3</strong> Transitional provisions – Grade / Level / Class 1 and 2 Employees</p><p><strong>(a)</strong> Implementation of subclause 89.2 will be as follows:</p><p><strong>(i)</strong> where an Employer has the arrangement in subclause 89.2 in place for all or some Employees at the time this Agreement commences operation, it will be maintained;</p><p><strong>(ii)</strong> where the Employer has the resources that could provide the clinical supervision described at subclause 89.2 to all or some Employees at the time this Agreement commences operation, it shall do so within 6 months subject to subclause 89.3(b);</p><p><strong>(iii)</strong> where the Employer does not have the resources that could provide the clinical supervision described at subclause 89.2 to all or some Employees at the time this Agreement commences operation, the Employer will implement such supervision when it is reasonably practicable to do so. The Allied Health Professionals Research and Practice Centre (however titled) will review, advise and assist the Employer with implementing such clinical supervision (including through networks across health services).</p><p><strong>(b)</strong> Where, at any time, an Employer does not provide the supervision at subclause</p><p><strong>89.2</strong> for an Employee/s, it must ensure that these Employees receive clinical supervision by a qualified and clinically appropriate Allied Health Professional.</p><p><strong>(c)</strong> Where because of exceptional circumstances both the Employee and Employer wish to apply an alternative to best meet the principles at subclause 89.2 or 89.3(b):</p><p><strong>(i)</strong> the Employer will notify the Union in writing (with a copy to the Employee);</p><p><strong>(ii)</strong> the parties will meet to discuss the matter; and</p><p><strong>(iii)</strong> in the event that the parties cannot agree, the matter is referred to either: A. the dispute resolution procedure in this Agreement (clause 14); or B. the Independent Dispute Resolution Panel (<a href="/eba/ebas/allied-health/consultation-disputes/14A-independent-dispute-resolution-panel.html">clause 14A</a>).</p><p><strong>89.4</strong> Grade / Level / Class 3 Employee and above</p><p><strong>(a)</strong> The Employer will ensure that all Employees Grade/Level/Class 3 (or equivalent) are clinically supervised by an appropriately qualified and clinically appropriate Allied Health Professional.</p><p><strong>(b)</strong> The Employer will ensure that all Employees Grade/Level/Class 4 (or equivalent) or above performing clinical work are clinically supervised and guided by an appropriately qualified and clinically appropriate:</p><p><strong>(i)</strong> Allied Health Professional; or</p><p><strong>(ii)</strong> Doctor of Medicine.</p><p><strong>(c)</strong> Where the Employer employs less than 25 Employees covered by this Agreement, the Employer will do what is required by subclause 89.4(a) and (b) where practicable.</p><p><strong>89.5</strong> Director/Deputy Director of Allied Health</p><p><strong>(a)</strong> The Employer recognises the importance of Allied Health and Allied Health Professionals to it and its patients and the importance of having Allied Health Professionals in senior management roles.</p><p><strong>(b)</strong> A Director/Deputy Director of Allied Health (however their position is titled) will be an Allied Health Professional.</p><p><strong>(c)</strong> Where:</p><p><strong>(i)</strong> at the commencement of the Agreement the Employer has a Director/Deputy Director of Allied Health; or</p><p><strong>(ii)</strong> the Victorian Government has providing funding to an Employer for a Director/Deputy Director of Allied Health position; the positions will be maintained during the life of this Agreement.</p><p><strong>89.6</strong> Definition of Allied Health Professional In this clause 89, Allied Health Professional means an employee working in a profession covered by this Agreement, a Dietitian, an Audiologist, or a Psychologist.</p>',37)])])}const g=t(a,[["render",n]]);export{m as __pageData,g as default};
